# Shapes module - abstract base classes and implementations
# Demonstrates cross-module inheritance with abstract classes

from colors import Color, ColorType, get_color_type

@abstract
class Shape:
    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def get_type(self) -> str: ...

class Rectangle(Shape):
    width: float
    height: float
    fill_color: Color

    def __init__(self, width: float, height: float, color: Color):
        super().__init__("Rectangle")
        self.width = width
        self.height = height
        self.fill_color = color

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_type(self) -> str:
        return "rectangle"

    def get_color(self) -> str:
        return self.fill_color.name

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_type(self) -> str:
        return "circle"

struct Dimensions:
    width: float
    height: float

    def area(self) -> float:
        return self.width * self.height

