# Utility functions module
# Demonstrates higher-order processing of imported types

from shapes import Shape, Rectangle, Circle
from colors import ColorType, get_color_type

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def count_by_type(shapes: list[Shape], shape_type: str) -> int:
    count: int = 0
    for s in shapes:
        if s.get_type() == shape_type:
            count = count + 1
    return count

def create_report(rect: Rectangle, circ: Circle) -> str:
    rect_area: float = rect.area()
    circ_area: float = circ.area()
    result: float = rect_area - circ_area
    return "Area difference: " + str(result)
